#include<bits/stdc++.h>
using namespace std;
const int N=200005;
int n,m1,m2,cntd,cnti,ans,td[N],ti[N],posd[N][2],posi[N][2];
bool vis[N];
struct flight
{
    int a,b;
} d[N],inter[N];
bool cmp(flight x,flight y)
{
    return x.a<y.a;
}
int check(int a[][2],int len,int x)
{
    int cnt=0,ans=0;
    memset(vis,0,sizeof(vis));
    for(int i=1;i<=len;i++)
    {
        if(a[i][1])
        {
            if(cnt<x)
            {
                cnt++,ans++;
                vis[a[i][0]]=1;
            }
        }
        else if(vis[a[i][0]]) cnt--;
    }
    return ans;
}
int main()
{
    cin>>n>>m1>>m2;
    for(int i=1;i<=m1;i++)
    {
        cin>>d[i].a>>d[i].b;
        td[++cntd]=d[i].a;
        td[++cntd]=d[i].b;
    }
    for(int i=1;i<=m2;i++)
    {
        cin>>inter[i].a>>inter[i].b;
        ti[++cnti]=inter[i].a;
        ti[++cnti]=inter[i].b;
    }
    sort(td+1,td+cntd+1);
    sort(ti+1,ti+cnti+1);
    sort(d+1,d+m1+1,cmp);
    sort(inter+1,inter+m2+1,cmp);
    for(int i=1;i<=m1;++i)
    {
        d[i].a=lower_bound(td+1,td+cntd+1,d[i].a)-td;
        d[i].b=lower_bound(td+1,td+cntd+1,d[i].b)-td;
        posd[d[i].a][0]=posd[d[i].b][0]=i;
        posd[d[i].a][1]=1;
    }
    for(int i=1;i<=m2;++i)
    {
        inter[i].a=lower_bound(ti+1,ti+cnti+1,inter[i].a)-ti;
        inter[i].b=lower_bound(ti+1,ti+cnti+1,inter[i].b)-ti;
        posi[inter[i].a][0]=posi[inter[i].b][0]=i;
        posi[inter[i].a][1]=1;
    }
    for(int i=0;i<=n;i++) ans=max(ans,check(posd,cntd,i)+check(posi,cnti,n-i));
    cout<<ans;
    return 0;
}
